    dlib::load_image(image, imgPath);
    dlib::pyramid_up(imgPath);

    long long detectTime = cv::getTickCount();
    vector<dlib::rectangle> detections = detector(image, 1);
    detectTime = cv::getTickCount() - detectTime;
    cout << "detect time : " << 1000 * detectTime / cv::getTickFrequency() << " ms" << endl;
